\begin{theorem}\label{thm-dichotomy}
Let $\m A$ be a finite algebra from a congruence modular variety.

Then, $\palg{\m A}=\ppoly$ or $\palg{\m A}\subseteq \circuittwo{\mathsf{NC}^2}{\mathsf{\MON}} $
\end{theorem}

