\begin{theorem}\label{solv-characterize}
    Let $\m A$ be a finite solvable Malcev algebra. Then there exists sequence of primes $p_1, \ldots, p_h$ such that
    \[
    \palg{\m A} \subseteq \nudet{p_1} \circ \ldots \circ \nudet{p_h}
    \]
\end{theorem}

